1	#!/usr/bin/env node
2	/**
3	 * Stand up a disposable prod test user and print its session JSON.
4	 *
5	 *   node provision.mjs <label>            # register + pod + env + wait ready
6	 *   node provision.mjs <label> --reuse    # reuse the cached user for <label> if it exists
7	 *
8	 * Writes `.state/users/<label>.json` (gitignored) so a scenario can be re-run against the same
9	 * user, and so a subagent that hits a budget wall can just provision a new one and carry on.
10	 */
11	import { mkdirSync, readFileSync, writeFileSync, existsSync } from 'node:fs';
12	import {
13	  provisionUser,
14	  budget,
15	  podBase,
16	  agentEnvFromSdk,
17	  mergePodEnv,
18	  waitPodReady,
19	  waitPodSettled,
20	} from './lib/gateway.mjs';
21	import { STATE_DIR } from './lib/paths.mjs';
22	
23	const label = process.argv[2] ?? 'scn';
24	const reuse = process.argv.includes('--reuse');
25	const file = `${STATE_DIR}/users/${label}.json`;
26	
27	/** Load a cached user, refreshing its JWT (12h TTL) and re-asserting pod env. */
28	export async function loadUser(lbl = label) {
29	  const f = `${STATE_DIR}/users/${lbl}.json`;
30	  if (!existsSync(f)) return null;
31	  const u = JSON.parse(readFileSync(f, 'utf8'));
32	  const { mintSession } = await import('./lib/jwt.mjs');
33	  const session = mintSession(u.userId, u.email); // always re-mint: cheap, never stale
34	  return { ...u, session, token: session.accessToken, pod: podBase() };
35	}
36	
37	/** Provision (or reuse) and guarantee: pod exists, agent keys loaded, pod ready. */
38	export async function getUser(lbl = label, { fresh = false } = {}) {
39	  if (!fresh) {
40	    const cached = await loadUser(lbl);
41	    if (cached) {
42	      // Re-assert env (a no-op PUT is skipped, so this usually does NOT restart the pod).
43	      const { changed } = await mergePodEnv(cached.token, agentEnvFromSdk()).catch(() => ({ changed: false }));
44	      await waitPodReady(cached.token).catch(() => {});
45	      if (changed) await waitPodSettled(cached.token);
46	      return cached;
47	    }
48	  }
49	  const u = await provisionUser({ label: lbl });
50	  mkdirSync(`${STATE_DIR}/users`, { recursive: true });
51	  writeFileSync(`${STATE_DIR}/users/${lbl}.json`, JSON.stringify({ email: u.email, userId: u.userId }, null, 2));
52	  return u;
53	}
54	
55	if (import.meta.url === `file://${process.argv[1]}`) {
56	  const u = await getUser(label, { fresh: !reuse });
57	  const b = await budget(u.token).catch((e) => ({ error: String(e) }));
58	  console.log(
59	    JSON.stringify(
60	      { label, email: u.email, userId: u.userId, pod: u.pod, token: u.token, budget: b },
61	      null,
62	      2,
63	    ),
64	  );
65	  console.log(`\n# pod namespace: user-${u.userId}\n# state: ${file}`);
66	}
67

