1	/**
2	 * `integration-demo/message.received` — the inbound producer for the demo integration.
3	 *
4	 * The demo space exists so the event pipeline can be exercised end-to-end **without a real
5	 * provider account**: you point any HMAC-signing caller (a test harness, `curl`, webhook.site)
6	 * at this def's inbound path and it behaves exactly like Slack/Telegram/etc. It is therefore the
7	 * space every live scenario uses to inject inbound events (`sdk/org/scenarios/`).
8	 *
9	 * Verification is the declarative `hmac` VerifySpec — SHA-256 over the raw body, hex-encoded,
10	 * presented as `x-demo-signature: sha256=<hex>`, keyed by `INTEGRATION_DEMO_WEBHOOK_SECRET`
11	 * (inside this space's own `INTEGRATION_DEMO_` env namespace, so it satisfies containment).
12	 * `emit` runs only AFTER the host has verified the signature, and is pure — no i/o.
13	 *
14	 * Body shape (deliberately Telegram-ish, so the demo doubles as a stand-in for a messaging
15	 * provider):
16	 *
17	 *   { "message": { "message_id": 1, "text": "hello", "chat": { "id": "c1" },
18	 *                  "from": { "id": "u1", "username": "ada" } } }
19	 *
20	 * Non-message payloads and empty/absent text emit nothing (`[]`) — the filter lives here, so no
21	 * agent ever wakes for a malformed or irrelevant delivery.
22	 *
23	 * Historical note: before the events migration this space declared its webhook in the
24	 * package.json `lmthing.webhook` descriptor block (the legacy `triggers:` path). That block was
25	 * removed when this def landed — a space must not carry both, or the legacy binding shadows the
26	 * emitter def.
27	 */
28	import type { Emitted, WebhookEmitterDef, WebhookInbound } from '@lmthing/core';
29	
30	interface DemoFrom {
31	  id?: string | number;
32	  username?: string;
33	  is_bot?: boolean;
34	}
35	
36	interface DemoMessage {
37	  message_id?: string | number;
38	  text?: string;
39	  chat?: { id?: string | number };
40	  from?: DemoFrom;
41	}
42	
43	interface DemoUpdate {
44	  message?: DemoMessage;
45	}
46	
47	const def: WebhookEmitterDef = {
48	  type: 'webhook',
49	  path: 'demo',
50	  verify: {
51	    type: 'hmac',
52	    algo: 'sha256',
53	    encoding: 'hex',
54	    header: 'x-demo-signature',
55	    prefix: 'sha256=',
56	  },
57	  secretEnv: 'INTEGRATION_DEMO_WEBHOOK_SECRET',
58	  emits: {
59	    'message.received': {
60	      payload: {
61	        text: 'string',
62	        from: 'string',
63	        chatId: 'string',
64	        threadKey: 'string?',
65	        userName: 'string?',
66	        raw: 'object',
67	      },
68	    },
69	  },
70	  emit(inbound: WebhookInbound): Emitted[] {
71	    const update = inbound.json as DemoUpdate | null | undefined;
72	    const message = update?.message;
73	    if (!message) return [];
74	
75	    const text = message.text;
76	    if (typeof text !== 'string' || text.length === 0) return [];
77	
78	    const from = message.from;
79	    if (!from || from.is_bot === true) return [];
80	    if (from.id === undefined || from.id === null) return [];
81	
82	    const chatId = message.chat?.id;
83	    if (chatId === undefined || chatId === null) return [];
84	
85	    const userName = typeof from.username === 'string' ? from.username : undefined;
86	    const threadKey =
87	      message.message_id === undefined || message.message_id === null
88	        ? undefined
89	        : String(message.message_id);
90	
91	    return [
92	      {
93	        event: 'message.received',
94	        payload: {
95	          text,
96	          from: String(from.id),
97	          chatId: String(chatId),
98	          userName,
99	          raw: update as unknown as Record<string, unknown>,
100	        },
101	        ...(threadKey ? { threadKey } : {}),
102	      },
103	    ];
104	  },
105	};
106	
107	export default def;
108

